import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getDashboardStats, getMyTasks, getTasks } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { isPast } from 'date-fns';

export default function Dashboard() {
  const { user, isAdmin } = useAuth();
  const [stats, setStats] = useState(null);
  const [recentTasks, setRecentTasks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [statsRes, tasksRes] = await Promise.all([
          getDashboardStats(),
          isAdmin ? getTasks() : getMyTasks()
        ]);
        setStats(statsRes.data.stats);
        setRecentTasks((tasksRes.data.tasks || []).slice(0, 5));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [isAdmin]);

  if (loading) return <div style={{textAlign:'center',padding:'50px',fontSize:'18px'}}>Loading...</div>;

  return (
    <div style={{padding:'30px',background:'#f8fafc',minHeight:'100vh'}}>

      {/* HEADER */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'30px'}}>
        <div>
          <h1 style={{fontSize:'32px',fontWeight:'700'}}>Dashboard</h1>
          <p style={{fontSize:'16px',color:'#555'}}>Welcome back, {user?.name} 👋</p>
        </div>
        {isAdmin && (
          <Link to="/projects" style={{padding:'10px 18px',background:'#16a34a',color:'#fff',borderRadius:'8px',textDecoration:'none',fontSize:'14px'}}>+ New Project</Link>
        )}
      </div>

      {/* STATS */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'20px',marginBottom:'30px'}}>
        {[
          { label: 'Total Tasks', value: stats?.total || 0, color: '#2563eb' },
          { label: 'In Progress', value: stats?.inProgress || 0, color: '#f59e0b' },
          { label: 'Completed', value: stats?.completed || 0, color: '#16a34a' },
          { label: 'Overdue', value: stats?.overdue || 0, color: '#dc2626' }
        ].map((item, i) => (
          <div key={i} style={{background:'#fff',padding:'25px',borderRadius:'12px',textAlign:'center',boxShadow:'0 5px 15px rgba(0,0,0,0.05)'}}>
            <div style={{fontSize:'28px',fontWeight:'700',color:item.color}}>{item.value}</div>
            <div style={{fontSize:'15px',marginTop:'5px',color:'#555'}}>{item.label}</div>
          </div>
        ))}
      </div>

      {/* PROGRESS */}
      {stats?.total > 0 && (
        <div style={{background:'#fff',padding:'20px',borderRadius:'12px',marginBottom:'25px'}}>
          <h3 style={{fontSize:'18px',marginBottom:'15px'}}>Overall Progress</h3>

          <div style={{display:'flex',height:'12px',borderRadius:'6px',overflow:'hidden'}}>
            <div style={{flex:stats.todo,background:'#d1d5db'}}></div>
            <div style={{flex:stats.inProgress,background:'#f59e0b'}}></div>
            <div style={{flex:stats.review,background:'#6366f1'}}></div>
            <div style={{flex:stats.completed,background:'#16a34a'}}></div>
          </div>
        </div>
      )}

      {/* TASKS */}
      <div style={{background:'#fff',padding:'20px',borderRadius:'12px'}}>
        <div style={{display:'flex',justifyContent:'space-between',marginBottom:'15px'}}>
          <h3 style={{fontSize:'18px'}}>Recent Tasks</h3>
          <Link to={isAdmin ? '/tasks' : '/my-tasks'} style={{fontSize:'14px',color:'#16a34a'}}>View all →</Link>
        </div>

        {recentTasks.length === 0 ? (
          <p style={{textAlign:'center',color:'#777'}}>No tasks yet</p>
        ) : (
          <div style={{display:'flex',flexDirection:'column',gap:'12px'}}>
            {recentTasks.map(task => (
              <div key={task._id} style={{padding:'15px',border:'1px solid #e5e7eb',borderRadius:'10px',display:'flex',justifyContent:'space-between',alignItems:'center'}}>

                <div>
                  <div style={{fontSize:'16px',fontWeight:'600'}}>{task.title}</div>
                  <div style={{fontSize:'13px',color:'#666',marginTop:'3px'}}>
                    {task.project?.name} {task.assignedTo && `• ${task.assignedTo.name}`}
                  </div>
                </div>

                <div style={{display:'flex',gap:'10px',alignItems:'center'}}>
                  {task.deadline && isPast(new Date(task.deadline)) && task.status !== 'completed' && (
                    <span style={{fontSize:'12px',color:'#dc2626'}}>Overdue</span>
                  )}
                  <span style={{fontSize:'12px',padding:'4px 10px',background:'#e5e7eb',borderRadius:'6px'}}>
                    {task.status}
                  </span>
                </div>

              </div>
            ))}
          </div>
        )}
      </div>

    </div>
  );
}
